-- {"operators": "CTE,INNER_JOIN,AGGREGATE", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "ORDER_LINE,WAREHOUSE,DISTRICT"}
WITH ol_by_district AS (SELECT OL_W_ID, OL_D_ID, SUM(OL_AMOUNT) AS district_revenue, COUNT(*) AS line_count FROM ORDER_LINE GROUP BY OL_W_ID, OL_D_ID), ol_by_warehouse AS (SELECT OL_W_ID, SUM(district_revenue) AS warehouse_revenue, SUM(line_count) AS total_lines, COUNT(*) AS district_count FROM ol_by_district GROUP BY OL_W_ID) SELECT w.W_ID, w.W_NAME, w.W_YTD, ow.warehouse_revenue, ow.total_lines, ow.district_count, d.D_ID, d.D_NAME, od.district_revenue, od.line_count FROM WAREHOUSE w JOIN ol_by_warehouse ow ON w.W_ID = ow.OL_W_ID JOIN DISTRICT d ON w.W_ID = d.D_W_ID JOIN ol_by_district od ON d.D_W_ID = od.OL_W_ID AND d.D_ID = od.OL_D_ID;
